import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";const i=JSON.parse(`{"title":"Porting to 26.1 Snapshots","description":"Guidelines for porting to snapshots of Minecraft 26.1, the upcoming version of Minecraft.","frontmatter":{"title":"Porting to 26.1 Snapshots","description":"Guidelines for porting to snapshots of Minecraft 26.1, the upcoming version of Minecraft.","authors":["cassiancc"],"resources":{"./26.1/fabric-api":"Fabric API 26.1 Porting Guide","https://minecraft.wiki/w/Java_Edition_26.1":"Java Edition 26.1 - Minecraft Wiki","https://github.com/ChampionAsh5357/neoforged-github/blob/update/26.1/primers/26.1/index.md":"ChampionAsh5357's 1.21.11 -> 26.1 Migration Primers"},"files":[]},"headers":[],"relativePath":"26.1/develop/porting/index.md","filePath":"26.1/develop/porting/index.md","lastUpdated":1774467289000}`);var a={name:`26.1/develop/porting/index.md`};function o(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Porting to 26.1 Snapshots <a class="header-anchor" href="#h1" aria-label="Permalink to “Porting to 26.1 Snapshots”">​</a></h1><p>The upcoming 26.1 version of Minecraft is unobfuscated, as are its snapshots. With this in mind, you&#39;ll need to make more changes to your build scripts than usual in order to port to it.</p><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p>These docs discuss migrating from <strong>1.21.11</strong> to the snapshots of the upcoming <strong>26.1</strong>. If you&#39;re looking for another migration, switch to the target version by using the dropdown in the top-right corner.</p></div><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to “Prerequisites”">​</a></h2><p>If your mod is still using Fabric&#39;s Yarn Mappings, you&#39;ll first need to <a href="./../../../develop/porting/mappings/">migrate your mod to Mojang&#39;s official mappings</a> before porting to 26.1.</p><p>If you are using IntelliJ IDEA, you will also need to update it to <code>2025.3</code> or higher for full Java 25 support.</p><h2 id="build-script" tabindex="-1">Updating the Build Script <a class="header-anchor" href="#build-script" aria-label="Permalink to “Updating the Build Script”">​</a></h2><p>Start by updating your mod&#39;s <code>gradle/wrapper/gradle-wrapper.properties</code>, <code>gradle.properties</code>, and <code>build.gradle</code> to the latest versions.</p><ol><li>Update Gradle to the latest version by running the following command: <code>./gradlew wrapper --gradle-version latest</code></li><li>Bump Minecraft, Fabric Loader, Fabric Loom and Fabric API, either in <code>gradle.properties</code> (recommended) or in <code>build.gradle</code>. Find the recommended versions of the Fabric components on the <a href="https://fabricmc.net/develop/" target="_blank" rel="noreferrer">Fabric Develop site</a>. <ul><li>Note that, since 26.1 snapshots are not stable versions of Minecraft, you will need to select this version manually from the dropdown.</li></ul></li><li>At the top of <code>build.gradle</code>, change the version of Loom you are using from <code>id &quot;fabric-loom&quot;</code> to <code>id &quot;net.fabricmc.fabric-loom&quot;</code>. If you specify Loom in <code>settings.gradle</code>, change it there as well.</li><li>Remove the <code>mappings</code> line from the dependencies section of <code>build.gradle</code>.</li><li>Replace any instances of <code>modImplementation</code> or <code>modCompileOnly</code> with <code>implementation</code> and <code>compileOnly</code>.</li><li>Remove or replace any mods made for versions before 26.1 with versions compatible with this update. <ul><li>No existing mods for 1.21.11 or older versions of Minecraft will work on 26.1, even as a compile-only dependency.</li></ul></li><li>Replace any mentions of <code>remapJar</code> with <code>jar</code>.</li><li>Refresh Gradle by using the refresh button in the top-right corner of IntelliJ IDEA. If this button is not visible, you can force caches to be cleared by running <code>./gradlew --refresh-dependencies</code>.</li></ol><h2 id="porting-guides" tabindex="-1">Updating the Code <a class="header-anchor" href="#porting-guides" aria-label="Permalink to “Updating the Code”">​</a></h2><p>After the build script has been updated to 26.1, you can now go through your mod and update any code that has changed to make it compatible with the snapshot.</p><div class="warning custom-block"><p class="custom-block-title">IMPORTANT</p><p>Because Minecraft 26.1 is still in the snapshot stage, documentation on specific changes is still lacking. Good luck, you&#39;re on your own!</p></div><ul><li><a href="./fabric-api">Fabric API 26.1 Porting Guide</a> lists the renames made to Fabric API in 26.1 snapshots to match Mojang&#39;s names.</li><li><a href="https://minecraft.wiki/w/Java_Edition_26.1" target="_blank" rel="noreferrer"><em>Java Edition 26.1</em> on the Minecraft Wiki</a> is an unofficial summary of the contents of the update.</li><li><a href="https://github.com/neoforged/.github/blob/main/primers/26.1/index.md" target="_blank" rel="noreferrer">NeoForge&#39;s <em>Minecraft 1.21.11 -&gt; 26.1 Mod Migration Primer</em></a> covers migrating from 1.21.11 to 26.1, focusing only on vanilla code changes. <ul><li>Please note that the linked article is third-party material, not maintained by Fabric. It&#39;s under copyright of @ChampionAsh5357, and licensed under <a href="https://creativecommons.org/licenses/by/4.0/" target="_blank" rel="noreferrer">Creative Commons Attribution 4.0 International</a>.</li></ul></li></ul>`,13)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};